#!/usr/bin/env node
/**
 * inject-provenance.cjs — Wave 5 P1 batch 3
 *
 * Injects a small "Generated by visual-explainer" provenance footer into a
 * generated HTML file (slide deck, diagram, recap, etc.) so downstream
 * viewers can trace the source. Off by default — enable with the
 * VE_PROVENANCE=1 environment variable or the --enabled flag.
 *
 * Usage:
 *   node inject-provenance.cjs --in deck.html --out deck.html [--source path/to/source.md]
 *
 * Idempotent: if a footer marker already exists, the file is left alone.
 */
'use strict';

const fs = require('fs');
const path = require('path');

const MARKER = '<!-- ve-provenance:v1 -->';

function buildFooter({ source, generatedAt, tool }) {
  return [
    MARKER,
    '<footer style="font:12px/1.4 system-ui,sans-serif;color:#888;padding:8px 12px;border-top:1px solid #eee;margin-top:24px;">',
    `  Generated by <strong>${tool}</strong>`,
    source ? `from <code>${escapeHtml(source)}</code>` : '',
    `at ${generatedAt}.`,
    '</footer>',
  ].filter(Boolean).join(' ');
}

function escapeHtml(s) {
  return String(s).replace(/[&<>"']/g, (c) => ({
    '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;',
  }[c]));
}

function injectProvenance(html, opts) {
  if (html.includes(MARKER)) return html; // idempotent
  const footer = buildFooter(opts);
  const idx = html.toLowerCase().lastIndexOf('</body>');
  if (idx === -1) return html + '\n' + footer + '\n';
  return html.slice(0, idx) + footer + '\n' + html.slice(idx);
}

function isEnabled(argv) {
  if (argv.includes('--enabled')) return true;
  if (process.env.VE_PROVENANCE === '1') return true;
  return false;
}

function parseArgs(argv) {
  const out = {};
  for (let i = 0; i < argv.length; i++) {
    const k = argv[i];
    if (k === '--in') out.in = argv[++i];
    else if (k === '--out') out.out = argv[++i];
    else if (k === '--source') out.source = argv[++i];
    else if (k === '--tool') out.tool = argv[++i];
  }
  return out;
}

function main() {
  const argv = process.argv.slice(2);
  if (!isEnabled(argv)) {
    console.error('ve-provenance: disabled (set VE_PROVENANCE=1 or pass --enabled)');
    process.exit(0);
  }
  const args = parseArgs(argv);
  if (!args.in) {
    console.error('Usage: inject-provenance.cjs --in file.html [--out file.html] [--source src] [--tool name]');
    process.exit(2);
  }
  const inPath = path.resolve(args.in);
  const outPath = path.resolve(args.out || args.in);
  const html = fs.readFileSync(inPath, 'utf8');
  const result = injectProvenance(html, {
    source: args.source,
    generatedAt: new Date().toISOString(),
    tool: args.tool || 'visual-explainer',
  });
  fs.writeFileSync(outPath, result);
  console.error(`ve-provenance: wrote ${outPath}`);
}

if (require.main === module) main();

module.exports = { injectProvenance, buildFooter, isEnabled, MARKER };
